#include <iostream>
#include <algorithm>
using namespace std;
int a[10005];
int main()
{
    int n;
    cin>>n;
    for(int i=2;i<=n;i++)
    {
        int temp=i;
        for(int j=2;j<=i;j++)
        {
            while(!(temp%j))
            {
                a[j]++;
                temp/=j;
            }
        }
    }
    for(int i=2;i<=n;i++)
    {
        if(a[i])
        {
            cout<<i<<" "<<a[i]<<endl;
        }
    }
    return 0;
}
